+/// Find an available TCP port.
+fn find_available_port() -> Result<u16, String> {
+    use std::net::TcpListener;
+    let listener = TcpListener::bind("127.0.0.1:0").map_err(|e| format!("Bind failed: {e}"))?;
+    let port = listener
+        .local_addr()
+        .map_err(|e| format!("Get addr failed: {e}"))?
+        .port();
+    Ok(port)
+}
+
+/// Wait for SSH server to be ready.
+fn wait_for_ssh(key_path: &Path, port: u16) -> Result<(), String> {
+    let max_attempts = 30;
+    let delay = Duration::from_millis(500);
+
+    for attempt in 1..=max_attempts {
+        let status = Command::new("ssh")
+            .args([
+                "-o",
+                "StrictHostKeyChecking=no",
+                "-o",
+                "UserKnownHostsFile=/dev/null",
+                "-o",
+                "BatchMode=yes",
+                "-o",
+                "ConnectTimeout=2",
+                "-i",
+                key_path.to_str().unwrap(),
+                "-p",
+                &port.to_string(),
+                "root@localhost",
+                "echo",
+                "ready",
+            ])
+            .stdout(Stdio::null())
+            .stderr(Stdio::null())
+            .status();
+
+        if let Ok(s) = status {
+            if s.success() {
+                return Ok(());
+            }
+        }
+
+        if attempt < max_attempts {
+            std::thread::sleep(delay);
+        }
+    }
+
+    Err("SSH server did not become ready in time".to_string())
+}
