+/// Create a sources.toml config with an SSH source.
+fn create_ssh_sources_config(
+    config_dir: &Path,
+    source_name: &str,
+    host: &str,
+    port: u16,
+    identity_file: &Path,
+    paths: &[&str],
+) {
+    let paths_toml: String = paths.iter().map(|p| format!("\"{}\"", p)).collect::<Vec<_>>().join(", ");
+
+    let config_content = format!(
+        r#"[[sources]]
+name = "{source_name}"
+type = "ssh"
+host = "{host}"
+port = {port}
+identity_file = "{identity_file}"
+paths = [{paths_toml}]
+sync_schedule = "manual"
+"#,
+        source_name = source_name,
+        host = host,
+        port = port,
+        identity_file = identity_file.display(),
+        paths_toml = paths_toml,
+    );
+
+    let config_file = config_dir.join("cass").join("sources.toml");
+    fs::create_dir_all(config_file.parent().unwrap()).unwrap();
+    fs::write(&config_file, config_content).unwrap();
+}
