+        r#"Host {host_alias}
+    HostName localhost
+    User root
+    Port {port}
+    IdentityFile {identity_file}
+    StrictHostKeyChecking no
+    UserKnownHostsFile /dev/null
+"#,
+        host_alias = host_alias,
+        port = port,
+        identity_file = identity_file.display(),
